                primary_codes.add(code)
        if not primary_codes:
            # if no 'first' marked, take first code if exists
            for entry in cpcs:
                code = entry.get('code')
                if code:
                    primary_codes.add(code)
                    break
        if not primary_codes:
            continue
        if assignee in assignee_to_codes:
            assignee_to_codes[assignee].update(primary_codes)
        else:
            assignee_to_codes[assignee] = set(primary_codes)

# convert sets to sorted lists
out = {k: sorted(list(v)) for k,v in assignee_to_codes.items()}
